// Parse audit JSON and format Slack message
const rawOutput = $input.first().json.stdout;
const audit = JSON.parse(rawOutput);
const { summary } = audit;

// Calculate health score (mirrors audit-visual-health.mjs logic)
const score = Math.max(0, 100 - (summary.high * 15) - (summary.medium * 5) - (summary.low * 2));
let status;
if (score >= 90) status = 'EXCELLENT';
else if (score >= 70) status = 'GOOD';
else if (score >= 50) status = 'NEEDS ATTENTION';
else status = 'CRITICAL';

// Count categories from registry (approximate from issues)
const categories = new Set();
let totalSizeKB = 0;
for (const issue of audit.issues) {
  if (issue.image) {
    const parts = issue.image.split('/');
    if (parts.length >= 3) categories.add(parts[2]);
  }
  if (issue.sizeKB) totalSizeKB += issue.sizeKB;
}

const totalSizeMB = (totalSizeKB / 1024).toFixed(0);

// Build top actions
const actions = [];
const placeholders = audit.issues.filter(i => i.type === 'placeholder');
const oversized = audit.issues.filter(i => i.type === 'oversized');
const duplicates = audit.issues.filter(i => i.type === 'duplicate-hero');

if (placeholders.length > 0) {
  actions.push(`Replace ${placeholders.length} placeholder(s): ${placeholders.slice(0, 3).map(i => i.file).join(', ')}`);
}
if (oversized.length > 0) {
  const savingsMB = (oversized.reduce((sum, i) => sum + (i.sizeKB - 2000), 0) / 1024).toFixed(0);
  actions.push(`Optimize ${oversized.length} oversized images (~${savingsMB}MB savings potential)`);
}
if (duplicates.length > 0) {
  actions.push(`Fix ${duplicates.length} duplicate hero image(s) in blog posts`);
}
if (actions.length === 0) {
  actions.push('No urgent actions required');
}

// Score emoji
let scoreEmoji;
if (score >= 90) scoreEmoji = ':white_check_mark:';
else if (score >= 70) scoreEmoji = ':large_blue_circle:';
else if (score >= 50) scoreEmoji = ':warning:';
else scoreEmoji = ':red_circle:';

const slackMessage = `:mag: *Weekly Visual Health Report*\n\n${scoreEmoji} *Score: ${score}/100* (${status})\n\n:bar_chart: *Issues:*\n\u2022 :red_circle: HIGH: ${summary.high} (placeholders in production)\n\u2022 :large_yellow_circle: MEDIUM: ${summary.medium} (duplicate heroes)\n\u2022 :large_blue_circle: LOW: ${summary.low} (oversized images)\n\u2022 :information_source: INFO: ${summary.info} (orphaned images)\n\n:chart_with_upwards_trend: *Registry:* ${audit.issues.length > 0 ? summary.total : 0} total issues found\n\n:clipboard: *Top Actions:*\n${actions.map((a, i) => `${i + 1}. ${a}`).join('\n')}\n\n_Timestamp: ${audit.timestamp}_\n_Run \`vis report --html\` for full details_`;

return [{ json: { text: slackMessage, score, status, summary, timestamp: audit.timestamp } }];
